import React, { useState, useEffect } from 'react';
import axios from 'axios';
import '../../Styles/Global.css';
import PlantList from './PlantList';

function ProductManager() {
  const [plant, setPlant] = useState({
    name: '',
    price: '',
    category: '',
    description: '',
    stock: '',
    care: '',
  });

  const [plants, setPlants] = useState([]); // list of all plants
  const [image, setImage] = useState(null);

  const handleChange = (e) => {
    setPlant({ ...plant, [e.target.name]: e.target.value });
  };

  const handleImageChange = (e) => {
    setImage(e.target.files[0]);
  };

  const fetchPlants = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/admin/products');
      setPlants(res.data);
    } catch (error) {
      console.error('Failed to fetch plants:', error);
    }
  };

  useEffect(() => {
    fetchPlants();
  }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();
    const formData = new FormData();
    Object.keys(plant).forEach(key => formData.append(key, plant[key]));
    if (image) formData.append('image', image);

    try {
      await axios.post('http://localhost:5000/api/admin/products', formData, {
        headers: {
          'Content-Type': 'multipart/form-data',
          Authorization: `Bearer ${localStorage.getItem('token')}`,
        },
      });
      alert('Plant added!');
      setPlant({ name: '', price: '', category: '', description: '', stock: '', care: '' });
      setImage(null);
      fetchPlants(); // refresh plant list
    } catch (err) {
      alert('Failed to add plant');
    }
  };

  return (
    <div style={{ display: 'flex', gap: '30px' }}>
      <form onSubmit={handleSubmit} style={{ flex: 1 }}>
        <input type="text" name="name" onChange={handleChange} placeholder="Plant Name" value={plant.name} />
        <input type="number" name="price" onChange={handleChange} placeholder="Price" value={plant.price} />
        <input name="category" onChange={handleChange} placeholder="Category" value={plant.category} />
        <textarea name="description" onChange={handleChange} placeholder="Description" value={plant.description} />
        <input name="stock" onChange={handleChange} placeholder="Stock Quantity" value={plant.stock} />
        <textarea name="care" onChange={handleChange} placeholder="Care Instructions" value={plant.care} />
        <input type="file" onChange={handleImageChange} />
        <button type="submit">Add Plant</button>
      </form>

      <div style={{ flex: 1 }}>
        <PlantList plants={plants} />
      </div>
    </div>
  );
}

export default ProductManager;
